export default function HandoffClarityNotice(){const [open,setOpen]=useState(false);const [ready,setReady]=useState(false);const reduced=useReducedMotion();return <section aria-labelledby="handoff-title" className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><motion.span animate={{x:ready?82:0}} transition={reduced?{duration:.12}:{duration:.18}} className="inline-block rounded-full bg-[#e0f2fe] px-2 py-1 text-xs font-bold text-[#075985]">{ready?'Ready':'Draft'}</motion.span><h2 id="handoff-title" className="mt-3 text-lg font-black text-[#111]">Ready for handoff</h2><p className="mt-1 text-sm text-[#4a4a4f]">Confirm the next owner can continue without a meeting.</p><button type="button" aria-expanded={open} aria-controls="handoff-checks" onClick={()=>setOpen(!open)} className="mt-3 min-h-11 rounded-xl border border-[#ececee] px-3 text-sm font-bold text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{open?'Hide checks':'Show checks'}</button><AnimatePresence>{open&&<motion.ul id="handoff-checks" initial={reduced?false:{height:0,opacity:0}} animate={{height:'auto',opacity:1}} exit={{height:0,opacity:0}} transition={reduced?{duration:.12}:{type:"spring",stiffness:310,damping:27}} className="mt-3 overflow-hidden text-sm text-[#4a4a4f]"><li>• Owner confirmed</li><li>• Next review scheduled</li></motion.ul>}</AnimatePresence><button type="button" aria-pressed={ready} onClick={()=>setReady(!ready)} className="mt-3 min-h-11 rounded-xl bg-[#111] px-3 text-sm font-bold text-white outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{ready?'Marked ready':'Mark ready'}</button><p aria-live="polite" className="sr-only">{ready?'Handoff marked ready.':open?'Handoff checks shown.':'Handoff checks hidden.'}</p></section>}
